mapper.update:
UPDATE moment
title = #{title}, content = #{content}, images = #{images}, status = #{status}, update_time = #{updateTime}
WHERE id = #{id}

mapper.select:
SELECT m.id, m.title, m.content, m.images AS images_json, m.like_count, m.view_count, m.status, m.create_time, m.update_time FROM moment m
INNER JOIN moment_tag mt ON m.id = mt.moment_id AND mt.tag_name = #{tagName}
AND m.title LIKE CONCAT('%', #{keyword}, '%')
AND m.status = #{status}
ORDER BY m.create_time DESC
